pr_body:
- Support for XML Encoding Rules for list keys as defined in RFC7950 Section 7.8.5
- Switch to existing lxml library dependency for ease of support for pretty printing

Given the following module example:
```
module a {
    namespace "http://a";
    prefix a;

    grouping alt-grouping {
        leaf leaf4 {
            type string;
        }
    }

    grouping list3-grouping {
        leaf leaf1 {
            type string;
        }
        leaf leaf8 {
            type string;
        }
        leaf leaf3 {
            type string;
        }
        leaf leaf2 {
            type string;
        }
        uses alt-grouping;
    }

    container container1 {
        list list1 {
            key "leaf1 leaf2";
            leaf leaf3 {
                type string;
            }
            leaf leaf1 {
                type string;
            }
            leaf leaf2 {
                type string;
            }
            leaf leaf4 {
                type string;
            }
        }
        list list2 {
            key "leaf1";
            leaf leaf2 {
                type string;
            }
            leaf leaf1 {
                type string;
            }
        }
        list list3 {
            key "leaf1 leaf2 leaf3 leaf4";
            leaf leaf9 {
                type string;
            }
            uses list3-grouping;
        }
    }
}
```

Now produces proper ordering of list keys for XML encoding:
```
$ pyang a.yang -f sample-xml-skeleton --sample-xml-skeleton-annotations
<?xml version='1.0' encoding='UTF-8'?>
<data xmlns="urn:ietf:params:xml:ns:netconf:base:1.0">
  <container1 xmlns="http://a">
    <list1>
      <!-- # entries: 0.. -->
      <!-- keys: [leaf1, leaf2] -->
      <leaf1>
        <!-- type: string -->
      </leaf1>
      <leaf2>
        <!-- type: string -->
      </leaf2>
      <leaf3>
        <!-- type: string -->
      </leaf3>
      <leaf4>
        <!-- type: string -->
      </leaf4>
    </list1>
    <list2>
      <!-- # entries: 0.. -->
      <!-- keys: [leaf1] -->
      <leaf1>
        <!-- type: string -->
      </leaf1>
      <leaf2>
        <!-- type: string -->
      </leaf2>
    </list2>
    <list3>
      <!-- # entries: 0.. -->
      <!-- keys: [leaf1, leaf2, leaf3, leaf4] -->
      <leaf1>
        <!-- type: string -->
      </leaf1>
      <leaf2>
        <!-- type: string -->
      </leaf2>
      <leaf3>
        <!-- type: string -->
      </leaf3>
      <leaf4>
        <!-- type: string -->
      </leaf4>
      <leaf9>
        <!-- type: string -->
      </leaf9>
      <leaf8>
        <!-- type: string -->
      </leaf8>
    </list3>
  </container1>
</data>
```

